from typing import List, Tuple, Optional

from pydantic import BaseModel, Field


class DataSettings(BaseModel):
    class_names: Tuple[str, ...] = (
        "road",
        "bike_line",
        "bus_stop",
        "continuous_line",
        "crosswalk",
        "hatching",
        "no_parking",
        "pictogram",
        "stop_line",
        "t'1_line",
        "t'2_line",
        "t1_line",
        "t2_line",
        "t3_line",
        "t'3_line",
        "t4_line",
        "yield_line",
    )
    input_channels_list: Tuple[str, ...] = ("intensity", "min_height", "max_height")
    output_channels_list: Tuple[str, ...] = ("semantic", "segmentation")
    ground_class: int = 1
    tile_radius_x: int = 256
    tile_radius_y: int = 256
    pixel_size: float = 0.05
    intensity_bounds: Tuple[int, int] = (0, 15_000)
    elevation_bounds: Tuple[float, float] = (-2.0, 2.0)
    augmentation: List[str] = Field(default_factory=list)

    @property
    def n_classes(self) -> int:
        return len(self.class_names)

    @property
    def input_channels(self) -> int:
        return len(self.input_channels_list)


class NetworkSettings(BaseModel):
    backbone: str = "efficientnetb5"
    batch_size: int = 2
    semantic_regularizer: float = 1.0
    segmentation_regularizer: float = 1.0
    segmentation_activation: Optional[str] = None
    linear_regularizer: float = 1.0
    linear_activation: Optional[str] = None
    refining_head: bool = False


class Settings(BaseModel):
    data: DataSettings = Field(default_factory=DataSettings)
    network: NetworkSettings = Field(default_factory=NetworkSettings)
